+        result.instance.error = err.message;
+      }
+    }
+
+    // 3. API counts
+    if (instanceName) {
+      try {
+        const chats = await getEvolutionChats(instanceName);
+        result.api.chatsCount = Array.isArray(chats) ? chats.length : 0;
+      } catch (err: any) {
+        result.api.error = err.message;
+      }
+    }
+
+    // 4. Database counts
+    const { count: instancesCount } = await admin
+      .from('whatsapp_instances')
+      .select('*', { count: 'exact', head: true })
+      .eq('user_id', user.id);
+
+    const { count: chatsCount } = await admin
+      .from('whatsapp_chats')
