+import { NextResponse } from 'next/server';
+import { createAdminClient } from '@/lib/supabase/admin';
+import { createServerSupabase } from '@/lib/supabase/server';
+import { getInstanceName } from '@/lib/evolution';
+
+// ============================================================
+// Debug Sync Endpoint
+// Returns instance status, counts from API and DB, and any errors
+// ============================================================
+export async function GET() {
+  try {
+    const supabase = await createServerSupabase();
+    const admin = createAdminClient();
+
+    const {
+      data: { user },
+    } = await supabase.auth.getUser();
+    if (!user) {
+      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
+    }
+
+    const result: any = {
+      user_id: user.id,
+      timestamp: new Date().toISOString(),
+      errors: [],
+    };
+
+    // 1. Check whatsapp_instances table for user's active instance
+    try {
+      const { data: instanceRow, error: instanceErr } = await admin
+        .from('whatsapp_instances')
+        .select('instance_name, is_active, created_at')
+        .eq('user_id', user.id)
+        .eq('is_active', true)
+        .limit(1);
+
+      if (instanceErr) {
+        result.errors.push({ source: 'whatsapp_instances', error: instanceErr.message });
+      } else if (instanceRow?.[0]) {
+        result.instance_from_table = instanceRow[0];
+      } else {
+        result.instance_from_table = null;
+      }
+    } catch (err: any) {
+      result.errors.push({ source: 'whatsapp_instances', error: err.message });
+    }
+
+    // 2. Check EVOLUTION_INSTANCE_NAME env var
+    result.env_instance_name = process.env.EVOLUTION_INSTANCE_NAME || null;
+
+    // 3. Determine the instance that would be used
+    let resolvedInstance = process.env.EVOLUTION_INSTANCE_NAME;
+    if (!resolvedInstance) {
+      const { data: recentChat } = await admin
+        .from('whatsapp_chats')
+        .select('instance_name')
+        .eq('user_id', user.id)
+        .order('updated_at', { ascending: false })
+        .limit(1);
+      if (recentChat?.[0]?.instance_name) {
+        resolvedInstance = recentChat[0].instance_name;
+      }
+    }
+    if (!resolvedInstance) {
+      resolvedInstance = await getInstanceName();
+    }
+    result.resolved_instance = resolvedInstance;
+
+    // 4. Get counts from database
+    try {
+      const [chatsCount, contactsCount, messagesCount] = await Promise.all([
+        admin.from('whatsapp_chats').select('*', { count: 'exact', head: true }).eq('user_id', user.id),
+        admin.from('whatsapp_contacts').select('*', { count: 'exact', head: true }).eq('user_id', user.id),
+        admin.from('whatsapp_messages').select('*', { count: 'exact', head: true }).eq('user_id', user.id),
+      ]);
+
+      result.db_counts = {
+        chats: chatsCount.count || 0,
+        contacts: contactsCount.count || 0,
+        messages: messagesCount.count || 0,
+      };
+    } catch (err: any) {
+      result.errors.push({ source: 'db_counts', error: err.message });
+    }
+
+    // 5. Try to get counts from Evolution API
+    try {
+      const { getEvolutionChats, getEvolutionContacts, getEvolutionMessages } = await import('@/lib/evolution');
+      
+      if (resolvedInstance) {
+        const apiChats = await getEvolutionChats(resolvedInstance);
+        result.api_counts = {
+          chats: apiChats?.length || 0,
+        };
+
+        // Get contacts from API
+        try {
+          const { getEvolutionContacts } = await import('@/lib/evolution');
+          const apiContacts = await getEvolutionContacts(resolvedInstance);
+          result.api_counts.contacts = apiContacts?.length || 0;
+        } catch {
+          result.api_counts.contacts = 'unavailable';
+        }
+
+        // Get sample of messages
+        try {
+          if (apiChats?.[0]?.remoteJid) {
+            const apiMessages = await getEvolutionMessages(resolvedInstance, apiChats[0].remoteJid);
+            result.api_counts.sample_messages = apiMessages?.length || 0;
+          }
+        } catch {
+          result.api_counts.sample_messages = 'unavailable';
+        }
+      }
+    } catch (err: any) {
+      result.errors.push({ source: 'api_counts', error: err.message });
+    }
+
+    return NextResponse.json(result);
+  } catch (error: any) {
+    console.error('[debug-sync]', error.message);
+    return NextResponse.json({ error: error.message }, { status: 500 });
+  }
+}
