+-- Migration: WhatsApp Sync Flow Improvements
+-- Creates tables for chats, contacts, instances and improves message handling
+-- All operations are idempotent using IF NOT EXISTS / ADD COLUMN IF NOT EXISTS
+
+-- 1. Create ENUM for message types if not exists
+DO $$
+BEGIN
+  IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'message_direction') THEN
+    CREATE TYPE message_direction AS ENUM ('inbound', 'outbound');
+  END IF;
+  IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'message_status') THEN
+    CREATE TYPE message_status AS ENUM ('pending', 'sent', 'delivered', 'read', 'failed');
+  END IF;
+END$$;
+
+-- 2. Create whatsapp_instances table (stores user's Evolution API instance associations)
+CREATE TABLE IF NOT EXISTS whatsapp_instances (
+  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
+  user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE NOT NULL,
+  instance_name TEXT NOT NULL,
+  api_key TEXT,
+  api_url TEXT,
+  is_active BOOLEAN DEFAULT false,
+  created_at TIMESTAMPTZ DEFAULT NOW(),
+  updated_at TIMESTAMPTZ DEFAULT NOW(),
+  UNIQUE(user_id, instance_name)
+);
+
+CREATE INDEX IF NOT EXISTS idx_whatsapp_instances_user_id ON whatsapp_instances(user_id);
+CREATE INDEX IF NOT EXISTS idx_whatsapp_instances_active ON whatsapp_instances(user_id, is_active) WHERE is_active = true;
+
+-- 3. Create whatsapp_chats table
+CREATE TABLE IF NOT EXISTS whatsapp_chats (
+  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
+  user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE NOT NULL,
+  instance_name TEXT NOT NULL,
+  remote_jid TEXT NOT NULL,
+  push_name TEXT,
+  profile_pic_url TEXT,
+  last_message TEXT,
+  last_message_at TIMESTAMPTZ,
+  unread_count INTEGER DEFAULT 0,
+  is_group BOOLEAN DEFAULT false,
+  pipeline_stage TEXT DEFAULT 'new',
+  created_at TIMESTAMPTZ DEFAULT NOW(),
+  updated_at TIMESTAMPTZ DEFAULT NOW(),
+  UNIQUE(instance_name, remote_jid)
+);
+
+CREATE INDEX IF NOT EXISTS idx_whatsapp_chats_user_id ON whatsapp_chats(user_id);
+CREATE INDEX IF NOT EXISTS idx_whatsapp_chats_instance ON whatsapp_chats(instance_name);
+CREATE INDEX IF NOT EXISTS idx_whatsapp_chats_updated ON whatsapp_chats(updated_at DESC);
+
+-- 4. Create whatsapp_contacts table
+CREATE TABLE IF NOT EXISTS whatsapp_contacts (
+  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
+  user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE NOT NULL,
