+  about TEXT,
+  created_at TIMESTAMPTZ DEFAULT NOW(),
+  updated_at TIMESTAMPTZ DEFAULT NOW(),
+  UNIQUE(instance_name, remote_jid)
+);
+
+CREATE INDEX IF NOT EXISTS idx_whatsapp_contacts_user_id ON whatsapp_contacts(user_id);
+CREATE INDEX IF NOT EXISTS idx_whatsapp_contacts_instance ON whatsapp_contacts(instance_name);
+
+-- 5. Add columns to whatsapp_messages table (if they don't exist)
+DO $$
+BEGIN
+  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'whatsapp_messages' AND column_name = 'message_key') THEN
+    ALTER TABLE whatsapp_messages ADD COLUMN message_key TEXT;
+  END IF;
+  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'whatsapp_messages' AND column_name = 'remote_jid') THEN
+    ALTER TABLE whatsapp_messages ADD COLUMN remote_jid TEXT;
+  END IF;
+  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'whatsapp_messages' AND column_name = 'from_me') THEN
+    ALTER TABLE whatsapp_messages ADD COLUMN from_me BOOLEAN DEFAULT false;
+  END IF;
+  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'whatsapp_messages' AND column_name = 'message_type') THEN
+    ALTER TABLE whatsapp_messages ADD COLUMN message_type TEXT;
+  END IF;
+  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'whatsapp_messages' AND column_name = 'sent_at') THEN
+    ALTER TABLE whatsapp_messages ADD COLUMN sent_at TIMESTAMPTZ;
+  END IF;
+END$$;
+
+-- 6. Create unique index for upsert operations on messages
+CREATE UNIQUE INDEX IF NOT EXISTS idx_whatsapp_messages_upsert 
+  ON whatsapp_messages(instance_name, remote_jid, message_key) 
+  WHERE message_key IS NOT NULL;
+
+-- 7. Create increment_unread_count function
+CREATE OR REPLACE FUNCTION increment_unread_count(p_instance_name TEXT, p_remote_jid TEXT)
+RETURNS void AS $$
+BEGIN
+  UPDATE whatsapp_chats 
+  SET unread_count = unread_count + 1, 
+      updated_at = NOW() 
+  WHERE instance_name = p_instance_name 
+    AND remote_jid = p_remote_jid;
+END;
+$$ LANGUAGE plpgsql SECURITY DEFINER;
+
+-- 8. Enable RLS on new tables
+ALTER TABLE whatsapp_instances ENABLE ROW LEVEL SECURITY;
+ALTER TABLE whatsapp_chats ENABLE ROW LEVEL SECURITY;
+ALTER TABLE whatsapp_contacts ENABLE ROW LEVEL SECURITY;
+
+-- 9. RLS Policies for whatsapp_instances
+CREATE POLICY "Users can view own whatsapp instances"
+  ON whatsapp_instances FOR SELECT USING (auth.uid() = user_id);
+CREATE POLICY "Users can insert own whatsapp instances"
+  ON whatsapp_instances FOR INSERT WITH CHECK (auth.uid() = user_id);
+CREATE POLICY "Users can update own whatsapp instances"
+  ON whatsapp_instances FOR UPDATE USING (auth.uid() = user_id);
+CREATE POLICY "Users can delete own whatsapp instances"
+  ON whatsapp_instances FOR DELETE USING (auth.uid() = user_id);
+
+-- 10. RLS Policies for whatsapp_chats
+CREATE POLICY "Users can view own whatsapp chats"
+  ON whatsapp_chats FOR SELECT USING (auth.uid() = user_id);
+CREATE POLICY "Users can insert own whatsapp chats"
+  ON whatsapp_chats FOR INSERT WITH CHECK (auth.uid() = user_id);
+CREATE POLICY "Users can update own whatsapp chats"
+  ON whatsapp_chats FOR UPDATE USING (auth.uid() = user_id);
+CREATE POLICY "Users can delete own whatsapp chats"
+  ON whatsapp_chats FOR DELETE USING (auth.uid() = user_id);
+
+-- 11. RLS Policies for whatsapp_contacts
+CREATE POLICY "Users can view own whatsapp contacts"
+  ON whatsapp_contacts FOR SELECT USING (auth.uid() = user_id);
+CREATE POLICY "Users can insert own whatsapp contacts"
+  ON whatsapp_contacts FOR INSERT WITH CHECK (auth.uid() = user_id);
+CREATE POLICY "Users can update own whatsapp contacts"
+  ON whatsapp_contacts FOR UPDATE USING (auth.uid() = user_id);
+CREATE POLICY "Users can delete own whatsapp contacts"
+  ON whatsapp_contacts FOR DELETE USING (auth.uid() = user_id);
+
+-- 12. Updated_at triggers for new tables
+CREATE OR REPLACE TRIGGER update_whatsapp_instances_updated_at
+  BEFORE UPDATE ON whatsapp_instances
+  FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();
+
+CREATE OR REPLACE TRIGGER update_whatsapp_chats_updated_at
+  BEFORE UPDATE ON whatsapp_chats
+  FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();
+
+CREATE OR REPLACE TRIGGER update_whatsapp_contacts_updated_at
+  BEFORE UPDATE ON whatsapp_contacts
+  FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();

