+import { NextResponse } from 'next/server';
+import { createAdminClient } from '@/lib/supabase/admin';
+import { createServerSupabase } from '@/lib/supabase/server';
+import { getEvolutionInstanceName } from '@/lib/evolution';
+import { getEvolutionChats } from '@/lib/evolution/api';
+import { getEvolutionContacts } from '@/lib/evolution';
+
+export async function GET() {
+  try {
+    const admin = createAdminClient();
+    const supabase = await createServerSupabase();
+    const { data: { user } } = await supabase.auth.getUser();
+
+    if (!user) {
+      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
+    }
+
+    // Resolve instance
+    let instanceName = process.env.EVOLUTION_INSTANCE_NAME;
+    let instanceSource = 'EVOLUTION_INSTANCE_NAME env';
+
+    if (!instanceName) {
+      const { data: instRow } = await admin
+        .from('whatsapp_instances')
+        .select('instance_name')
+        .eq('user_id', user.id)
+        .eq('is_active', true)
+        .maybeSingle();
+      if (instRow?.instance_name) {
+        instanceName = instRow.instance_name;
+        instanceSource = 'whatsapp_instances table';
+      }
+    }
+
+    if (!instanceName) {
+      const { data: latestRow } = await admin
+        .from('whatsapp_chats')
+        .select('instance_name')
+        .eq('user_id', user.id)
+        .order('updated_at', { ascending: false })
+        .limit(1)
+        .maybeSingle();
+      if (latestRow?.instance_name) {
+        instanceName = latestRow.instance_name;
+        instanceSource = 'whatsapp_chats most recent';
+      }
+    }
+
+    if (!instanceName) {
+      instanceName = await getEvolutionInstanceName();
+      instanceSource = 'getEvolutionInstanceName fallback';
+    }
+
+    const errors: string[] = [];
+    let apiChatsCount = 0, apiContactsCount = 0;
+    let dbChatsCount = 0, dbContactsCount = 0, dbMessagesCount = 0;
+
+    // --- API counts ---
+    try {
+      const { getEvolutionMessages } = await import('@/lib/evolution/api');
+      const apiChats = await getEvolutionChats(instanceName);
+      apiChatsCount = apiChats?.length || 0;
+    } catch (e: any) {
+      errors.push(`getEvolutionChats: ${e.message}`);
+    }
+
+    try {
+      const contacts = await getEvolutionContacts(instanceName);
+      apiContactsCount = contacts?.length || 0;
+    } catch (e: any) {
+      errors.push(`getEvolutionContacts: ${e.message}`);
+    }
+
+    // --- DB counts ---
+    try {
+      const { count: chatCount } = await admin
+        .from('whatsapp_chats')
+        .select('*', { count: 'exact', head: true })
+        .eq('user_id', user.id);
+      dbChatsCount = chatCount || 0;
+    } catch (e: any) {
+      errors.push(`whatsapp_chats count: ${e.message}`);
+    }
+
+    try {
+      const { count: contactCount } = await admin
+        .from('whatsapp_contacts')
+        .select('*', { count: 'exact', head: true })
+        .eq('user_id', user.id);
+      dbContactsCount = contactCount || 0;
+    } catch (e: any) {
+      errors.push(`whatsapp_contacts count: ${e.message}`);
+    }
+
+    try {
+      const { count: msgCount } = await admin
+        .from('whatsapp_messages')
+        .select('*', { count: 'exact', head: true })
+        .eq('user_id', user.id);
+      dbMessagesCount = msgCount || 0;
+    } catch (e: any) {
+      errors.push(`whatsapp_messages count: ${e.message}`);
+    }
+
+    return NextResponse.json({
+      instance_name: instanceName,
+      instance_source: instanceSource,
+      api: {
+        chats_count: apiChatsCount,
+        contacts_count: apiContactsCount,
+      },
+      database: {
+        chats_count: dbChatsCount,
+        contacts_count: dbContactsCount,
+        messages_count: dbMessagesCount,
+      },
+      errors,
+    }, { status: 200 });
+  } catch (error: any) {
+    console.error('[debug-sync]', error);
+    return NextResponse.json({ error: error.message }, { status: 500 });
+  }
+}
