+-- Migration: WhatsApp Sync Overhaul v2
+-- Non-destructive: creates tables/columns/indexes only if they don't exist
+
+-- ============================================================
+-- 1. ENUMs (add if not exists via DO block)
+-- ============================================================
+DO $$ BEGIN
+  CREATE TYPE evolution_event_type AS ENUM (
+    'MESSAGES_UPSERT', 'MESSAGES_UPDATE', 'SEND_MESSAGE',
+    'CONTACTS_UPDATE', 'CHATS_UPSERT', 'CONNECTION_UPDATE'
+  );
+EXCEPTION WHEN duplicate_object THEN null;
+END $$;
+
+DO $$ BEGIN
+  CREATE TYPE message_direction AS ENUM ('inbound', 'outbound');
+EXCEPTION WHEN duplicate_object THEN null;
+END $$;
+
+DO $$ BEGIN
+  CREATE TYPE message_status AS ENUM ('pending', 'sent', 'delivered', 'read', 'failed');
+EXCEPTION WHEN duplicate_object THEN null;
+END $$;
+
+-- ============================================================
+-- 2. whatsapp_instances table
+-- ============================================================
+CREATE TABLE IF NOT EXISTS whatsapp_instances (
+  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
+  user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE NOT NULL,
+  instance_name TEXT NOT NULL,
+  is_active BOOLEAN DEFAULT true,
+  created_at TIMESTAMPTZ DEFAULT NOW(),
+  updated_at TIMESTAMPTZ DEFAULT NOW()
+);
+
+CREATE UNIQUE INDEX IF NOT EXISTS idx_whatsapp_instances_user_active
+  ON whatsapp_instances(user_id) WHERE is_active = true;
+
+CREATE INDEX IF NOT EXISTS idx_whatsapp_instances_instance_name
+  ON whatsapp_instances(instance_name);
+
+ALTER TABLE whatsapp_instances ENABLE ROW LEVEL SECURITY;
+
+CREATE POLICY "Users can manage own whatsapp instances"
+  ON whatsapp_instances FOR ALL
+  USING (auth.uid() = user_id);
+
+-- ============================================================
+-- 3. whatsapp_contacts table
+-- ============================================================
+CREATE TABLE IF NOT EXISTS whatsapp_contacts (
+  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
+  user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE,
+  instance_name TEXT NOT NULL,
+  remote_jid TEXT NOT NULL,
+  push_name TEXT,
+  profile_pic_url TEXT,
+  about TEXT,
+  phone_normalized TEXT,
+  created_at TIMESTAMPTZ DEFAULT NOW(),
+  updated_at TIMESTAMPTZ DEFAULT NOW()
+);
+
+CREATE UNIQUE INDEX IF NOT EXISTS idx_whatsapp_contacts_unique
+  ON whatsapp_contacts(instance_name, remote_jid);
+
+CREATE INDEX IF NOT EXISTS idx_whatsapp_contacts_phone
+  ON whatsapp_contacts(phone_normalized);
+
+ALTER TABLE whatsapp_contacts ENABLE ROW LEVEL SECURITY;
+
+CREATE POLICY "Users can manage own whatsapp contacts"
+  ON whatsapp_contacts FOR ALL
+  USING (auth.uid() = user_id);
+
+CREATE TRIGGER update_whatsapp_contacts_updated_at
+  BEFORE UPDATE ON whatsapp_contacts
+  FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();
+
+-- ============================================================
+-- 4. whatsapp_chats table — extend existing or create
+-- ============================================================
+CREATE TABLE IF NOT EXISTS whatsapp_chats (
+  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
+  user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE,
+  instance_name TEXT NOT NULL,
+  remote_jid TEXT NOT NULL,
+  push_name TEXT,
+  profile_pic_url TEXT,
+  last_message TEXT,
+  last_message_at TIMESTAMPTZ,
+  unread_count INTEGER DEFAULT 0,
+  is_group BOOLEAN DEFAULT false,
+  pipeline_stage TEXT,
+  created_at TIMESTAMPTZ DEFAULT NOW(),
+  updated_at TIMESTAMPTZ DEFAULT NOW()
+);
+
+CREATE UNIQUE INDEX IF NOT EXISTS idx_whatsapp_chats_unique
+  ON whatsapp_chats(instance_name, remote_jid);
+
+CREATE INDEX IF NOT EXISTS idx_whatsapp_chats_updated_at
+  ON whatsapp_chats(updated_at DESC);
+
+CREATE INDEX IF NOT EXISTS idx_whatsapp_chats_user_instance
+  ON whatsapp_chats(user_id, instance_name);
+
+ALTER TABLE whatsapp_chats ENABLE ROW LEVEL SECURITY;
+
+CREATE POLICY "Users can manage own whatsapp chats"
+  ON whatsapp_chats FOR ALL
+  USING (auth.uid() = user_id);
+
+CREATE TRIGGER update_whatsapp_chats_updated_at
+  BEFORE UPDATE ON whatsapp_chats
+  FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();
+
+-- ============================================================
+-- 5. whatsapp_messages — add missing columns and indexes
+-- ============================================================
+DO $$ BEGIN
+  ALTER TABLE whatsapp_messages ADD COLUMN IF NOT EXISTS remote_jid TEXT;
+EXCEPTION WHEN duplicate_column THEN null;
+END $$;
+
+DO $$ BEGIN
+  ALTER TABLE whatsapp_messages ADD COLUMN IF NOT EXISTS from_me BOOLEAN;
+EXCEPTION WHEN duplicate_column THEN null;
+END $$;
+
+DO $$ BEGIN
+  ALTER TABLE whatsapp_messages ADD COLUMN IF NOT EXISTS push_name TEXT;
+EXCEPTION WHEN duplicate_column THEN null;
+END $$;
+
+DO $$ BEGIN
+  ALTER TABLE whatsapp_messages ADD COLUMN IF NOT EXISTS message_type TEXT;
+EXCEPTION WHEN duplicate_column THEN null;
+END $$;
+
+DO $$ BEGIN
+  ALTER TABLE whatsapp_messages ADD COLUMN IF NOT EXISTS sent_at TIMESTAMPTZ;
+EXCEPTION WHEN duplicate_column THEN null;
+END $$;
+
+DO $$ BEGIN
+  ALTER TABLE whatsapp_messages ADD COLUMN IF NOT EXISTS contact_name TEXT;
+EXCEPTION WHEN duplicate_column THEN null;
+END $$;
+
+DO $$ BEGIN
+  ALTER TABLE whatsapp_messages ADD COLUMN IF NOT EXISTS message_key TEXT;
+EXCEPTION WHEN duplicate_column THEN null;
+END $$;
+
+CREATE INDEX IF NOT EXISTS idx_whatsapp_messages_key
+  ON whatsapp_messages(message_key);
+
+CREATE UNIQUE INDEX IF NOT EXISTS idx_whatsapp_messages_unique
+  ON whatsapp_messages(instance_name, remote_jid, message_key);
+
+CREATE INDEX IF NOT EXISTS idx_whatsapp_messages_direction
+  ON whatsapp_messages(direction);
+
+-- ============================================================
+-- 6. increment_unread_count RPC
+-- ============================================================
+CREATE OR REPLACE FUNCTION increment_unread_count(p_instance TEXT, p_jid TEXT)
+RETURNS void LANGUAGE plpgsql SECURITY DEFINER AS $$
+BEGIN
+  UPDATE whatsapp_chats
+  SET unread_count = COALESCE(unread_count, 0) + 1,
+      updated_at = NOW()
+  WHERE instance_name = p_instance AND remote_jid = p_jid;
+END;
+$$;

