+// Audio Visualizer Component (Canvas-based circular visualizer)
+const AudioVisualizer = ({ isSpeaking }) => {
+  const canvasRef = useRef(null);
+  const animationRef = useRef(null);
+  const barsRef = useRef([]);
+  const decayRef = useRef(0);
