+    const centerX = canvas.width / 2;
+    const centerY = canvas.height / 2;
+    const barCount = 32;
+    
+    // Initialize bar heights
+    barsRef.current = Array(barCount).fill(0);
+    
+    const animate = () => {
+      ctx.clearRect(0, 0, canvas.width, canvas.height);
+      
+      const targetIntensity = isSpeaking ? 1.0 : 0.0;
+      decayRef.current += (targetIntensity - decayRef.current) * (isSpeaking ? 0.3 : 0.05);
+      
+      const intensity = decayRef.current;
+      
+      // Draw circular bars
+      for (let i = 0; i < barCount; i++) {
+        const angle = (i / barCount) * Math.PI * 2 - Math.PI / 2;
+        
+        // Animate individual bars
+        const targetHeight = isSpeaking ? 
+          15 + Math.random() * 25 * intensity : 
+          0;
+        
+        barsRef.current[i] += (targetHeight - barsRef.current[i]) * 0.2;
+        const barHeight = barsRef.current[i];
+        
+        const innerRadius = 25;
+        const outerRadius = innerRadius + barHeight;
+        
+        const x1 = centerX + Math.cos(angle) * innerRadius;
+        const y1 = centerY + Math.sin(angle) * innerRadius;
+        const x2 = centerX + Math.cos(angle) * outerRadius;
+        const y2 = centerY + Math.sin(angle) * outerRadius;
+        
+        // Gradient for bar
+        const gradient = ctx.createLinearGradient(x1, y1, x2, y2);
+        gradient.addColorStop(0, `rgba(79, 195, 247, ${0.6 * intensity})`);
+        gradient.addColorStop(1, `rgba(79, 195, 247, ${1.0 * intensity})`);
+        
+        ctx.beginPath();
+        ctx.moveTo(x1, y1);
+        ctx.lineTo(x2, y2);
+        ctx.strokeStyle = gradient;
+        ctx.lineWidth = 3;
+        ctx.lineCap = 'round';
+        ctx.stroke();
+      }
+      
+      // Draw center circle
+      ctx.beginPath();
+      ctx.arc(centerX, centerY, 20, 0, Math.PI * 2);
+      ctx.fillStyle = `rgba(79, 195, 247, ${0.3 + intensity * 0.5})`;
+      ctx.fill();
+      ctx.strokeStyle = `rgba(79, 195, 247, ${0.6 + intensity * 0.4})`;
