diff --git a/components/jarvis/AudioVisualizer.jsx b/components/jarvis/AudioVisualizer.jsx
--- a/components/jarvis/AudioVisualizer.jsx
+++ b/components/jarvis/AudioVisualizer.jsx
@@ -0,0 +1,112 @@
+"use client";
+
+import React, { useEffect, useRef } from 'react';
+
+const AudioVisualizer = ({ isSpeaking, color = "#4fc3f7" }) => {
+  const canvasRef = useRef(null);
+  const animationRef = useRef(null);
+  const dataRef = useRef(new Array(32).fill(0));
+
+  useEffect(() => {
+    const canvas = canvasRef.current;
+    if (!canvas) return;
+
+    const ctx = canvas.getContext('2d');
+    const width = canvas.width;
+    const height = canvas.height;
+    const centerX = width / 2;
+    const centerY = height / 2;
+    const radius = Math.min(width, height) / 3;
+
+    const render = () => {
+      ctx.clearRect(0, 0, width, height);
+
+      // Update mock data if speaking
+      if (isSpeaking) {
+        dataRef.current = dataRef.current.map(() => Math.random() * 20 + 5);
+      } else {
+        dataRef.current = dataRef.current.map(val => val * 0.9);
+      }
+
+      // Draw outer ring
+      ctx.beginPath();
+      ctx.arc(centerX, centerY, radius + 10, 0, Math.PI * 2);
+      ctx.strokeStyle = `${color}33`;
+      ctx.lineWidth = 1;
+      ctx.stroke();
+
+      // Draw inner glow
+      const gradient = ctx.createRadialGradient(centerX, centerY, 0, centerX, centerY, radius);
+      gradient.addColorStop(0, `${color}00`);
+      gradient.addColorStop(1, isSpeaking ? `${color}11` : `${color}05`);
+      ctx.fillStyle = gradient;
+      ctx.beginPath();
+      ctx.arc(centerX, centerY, radius, 0, Math.PI * 2);
+      ctx.fill();
+
+      // Draw frequency bars in a circle
+      const bars = dataRef.current.length;
+      for (let i = 0; i < bars; i++) {
+        const angle = (i / bars) * Math.PI * 2;
+        const amplitude = dataRef.current[i];
+        
+        const x1 = centerX + Math.cos(angle) * radius;
+        const y1 = centerY + Math.sin(angle) * radius;
+        const x2 = centerX + Math.cos(angle) * (radius + amplitude);
+        const y2 = centerY + Math.sin(angle) * (radius + amplitude);
+
+        ctx.beginPath();
+        ctx.moveTo(x1, y1);
+        ctx.lineTo(x2, y2);
+        ctx.strokeStyle = color;
+        ctx.lineWidth = 2;
+        ctx.lineCap = 'round';
+        ctx.stroke();
+
+        // Add a small dot at the end
+        ctx.beginPath();
+        ctx.arc(x2, y2, 1, 0, Math.PI * 2);
+        ctx.fillStyle = color;
+        ctx.fill();
+      }
+
+      // Draw center core
+      ctx.beginPath();
+      ctx.arc(centerX, centerY, radius - 15, 0, Math.PI * 2);
+      ctx.strokeStyle = `${color}66`;
+      ctx.lineWidth = 2;
+      ctx.stroke();
+
+      if (isSpeaking) {
+        ctx.shadowBlur = 10;
+        ctx.shadowColor = color;
+        ctx.beginPath();
+        ctx.arc(centerX, centerY, radius - 20, 0, Math.PI * 2);
+        ctx.fillStyle = `${color}22`;
+        ctx.fill();
+        ctx.shadowBlur = 0;
+      }
+
+      animationRef.current = requestAnimationFrame(render);
+    };
+
+    render();
+
+    return () => {
+      if (animationRef.current) {
+        cancelAnimationFrame(animationRef.current);
+      }
+    };
+  }, [isSpeaking, color]);
+
+  return (
+    <canvas 
+      ref={canvasRef} 
+      width={120} 
+      height={120} 
+      className="w-24 h-24 sm:w-32 sm:h-32"
+    />
+  );
+};
+
+export default AudioVisualizer;
