diff --git a/components/jarvis/TypewriterText.jsx b/components/jarvis/TypewriterText.jsx
--- a/components/jarvis/TypewriterText.jsx
+++ b/components/jarvis/TypewriterText.jsx
@@ -0,0 +1,32 @@
+"use client";
+
+import React, { useState, useEffect } from 'react';
+
+const TypewriterText = ({ text, speed = 20, onComplete, onUpdate }) => {
+  const [displayedText, setDisplayedText] = useState('');
+  const [index, setIndex] = useState(0);
+
+  useEffect(() => {
+    // Reset when text changes
+    setDisplayedText('');
+    setIndex(0);
+  }, [text]);
+
+  useEffect(() => {
+    if (index < text.length) {
+      const timeout = setTimeout(() => {
+        setDisplayedText((prev) => prev + text[index]);
+        setIndex((prev) => prev + 1);
+        if (onUpdate) onUpdate();
+      }, speed);
+
+      return () => clearTimeout(timeout);
+    } else if (onComplete) {
+      onComplete();
+    }
+  }, [index, text, speed, onComplete, onUpdate]);
+
+  return <>{displayedText}</>;
+};
+
+export default TypewriterText;
