+#!/usr/bin/env node
+
+import { existsSync, readdirSync, readFileSync, statSync } from 'node:fs';
+import { join, relative, resolve } from 'node:path';
+
+type PackageTreeStatus = 'ok' | 'missing' | 'stale' | 'extra-owned-files';
+
+type CodexHookStatusObj =
+  | { status: 'ok' }
+  | { status: 'missing' }
+  | { status: 'invalid'; reason: string };
+
+// ── Repo version ──────────────────────────────────────────────────────────────
+const repoRoot = resolve(process.cwd());
+const versionPath = resolve(repoRoot, 'plugins/version.json');
+interface VersionJson { version: string }
+const repoVersion: VersionJson = existsSync(versionPath)
+  ? JSON.parse(readFileSync(versionPath, 'utf8')) as VersionJson
+  : { version: 'unknown' };
+
+// ── Package-tree helpers ──────────────────────────────────────────────────────
+const OWNED_FILE_PATTERNS = [
+  /\.claude-plugin\//,
+  /^commands\//,
+  /^scripts\//,
+  /^README\.md$/,
+];
+
+function isOwnedPath(relativePath: string): boolean {
+  const normalized = relativePath.replace(/^\.\//, '');
+  return OWNED_FILE_PATTERNS.some((pattern) => pattern.test(normalized));
+}
+
+function collectOwnedFiles(dir: string, baseDir: string = dir): Map<string, string> {
+  const files = new Map<string, string>();
+  if (!existsSync(dir)) return files;
+  function walk(subDir: string): void {
+    const entries = readdirSync(subDir, { withFileTypes: true });
+    for (const entry of entries) {
+      const fullPath = join(subDir, entry.name);
+      const relPath = relative(baseDir, fullPath);
+      if (entry.isDirectory()) {
+        walk(fullPath);
+      } else if (isOwnedPath(relPath)) {
+        files.set(relPath, readFileSync(fullPath));
+      }
+    }
+  }
+  walk(dir);
+  return files;
+}
+
+function comparePackageTrees(sourceDir: string, targetDir: string): PackageTreeStatus {
+  const sourceFiles = collectOwnedFiles(sourceDir);
+  if (!existsSync(targetDir)) return 'missing';
+  const targetFiles = collectOwnedFiles(targetDir);
+  for (const [relPath, sourceContent] of sourceFiles.entries()) {
+    const targetContent = targetFiles.get(relPath);
+    if (targetContent === undefined) return 'stale';
+    if (targetContent !== sourceContent) return 'stale';
+  }
+  for (const relPath of targetFiles.keys()) {
+    if (!sourceFiles.has(relPath)) return 'extra-owned-files';
+  }
+  return 'ok';
+}
+
+// ── Codex hook status ────────────────────────────────────────────────────────
+function getCodexHookStatus(): CodexHookStatusObj {
+  const home = process.env.HOME ?? '/root';
+  const hookConfigPaths = [
+    resolve(home, '.config/Codex/hooks.json'),
+    resolve(home, '.config/codex/hooks.json'),
+  ];
+  let hookEntries: Array<Record<string, unknown>> = [];
+  for (const hookConfigPath of hookConfigPaths) {
+    if (existsSync(hookConfigPath)) {
+      try {
+        const raw = JSON.parse(readFileSync(hookConfigPath, 'utf8')) as Record<string, unknown>;
+        hookEntries =
+          (raw.hooksv2 as Array<Record<string, unknown>> | undefined) ??
+          (raw.hooks as Array<Record<string, unknown>> | undefined) ??
+          (raw.circuit as Array<Record<string, unknown>> | undefined) ??
+          [];
+        break;
+      } catch {
+        // ignore
+      }
+    }
+  }
+  if (hookEntries.length === 0) return { status: 'missing' };
+  const circuitHooks = hookEntries.filter(
+    (entry) => typeof (entry.command as string | undefined) === 'string',
+  );
+  if (circuitHooks.length === 0) return { status: 'missing' };
+  if (circuitHooks.length > 1) {
+    return { status: 'invalid', reason: `duplicate Circuit hooks: found ${circuitHooks.length} entries` };
+  }
+  const cmd = (circuitHooks[0].command as string) ?? '';
+  const binMatch = cmd.match(/^([^\s]+)/);
+  if (binMatch && !existsSync(binMatch[1])) {
+    return { status: 'invalid', reason: `launcher binary missing: ${binMatch[1]}` };
+  }
+  return { status: 'ok' };
+}
+
+// ── Runtime doctor ────────────────────────────────────────────────────────────
+interface PluginDoctorResult {
+  plugin: string;
+  runtime: string;
+  bundled: boolean;
+  healthy: boolean;
+}
+
+function checkPluginDoctor(pluginScript: string): PluginDoctorResult | null {
+  const { spawnSync } = require('node:child_process');
+  const result = spawnSync(process.execPath, [pluginScript, 'doctor'], {
+    encoding: 'utf8',
+    timeout: 30_000,
+  });
+  const raw = result.stdout + result.stderr;
+  const bundled = /runtime.*bundled/i.test(raw);
+  const healthy = result.status === 0 && bundled;
+  return {
+    plugin: 'circuit',
+    runtime: bundled ? 'bundled' : 'not-bundled',
+    bundled,
+    healthy,
+  };
+}
+
+// ── Build report ─────────────────────────────────────────────────────────────
+const home = process.env.HOME ?? '/root';
+const claudeSourceDir = resolve(repoRoot, 'plugins/claude');
+const codexSourceDir = resolve(repoRoot, 'plugins/circuit');
+
+const claudeInstalledPath = resolve(
+  home,
+  '.claude/plugins/cache/circuit-next/circuit',
+  repoVersion.version,
+);
+const codexCacheDir = resolve(home, '.codex/plugins/circuit-next-local');
+
+const claudeTreeStatus = comparePackageTrees(claudeSourceDir, claudeInstalledPath);
+const codexTreeStatus = comparePackageTrees(codexSourceDir, codexCacheDir);
+
+const pluginDoctor = (() => {
+  const doctorScript = resolve(claudeInstalledPath, 'scripts/circuit-next.mjs');
+  if (existsSync(doctorScript)) {
+    return checkPluginDoctor(doctorScript);
+  }
+  return null;
+})();
+
+const codexHookStatus = getCodexHookStatus();
+
+const report = {
+  repo_version: repoVersion.version,
+  claude: {
+    package_tree_status: claudeTreeStatus,
+    installed_path: claudeInstalledPath,
+    doctor: pluginDoctor,
+  },
+  codex: {
+    package_tree_status: codexTreeStatus,
+    cache_path: codexCacheDir,
+  },
+  codex_hook: codexHookStatus,
+};
+
+// ── Determine overall health ──────────────────────────────────────────────────
+const healthy =
+  claudeTreeStatus === 'ok' &&
+  codexTreeStatus === 'ok' &&
+  (pluginDoctor === null || pluginDoctor.healthy) &&
+  codexHookStatus.status === 'ok';
+
+// ── Output ───────────────────────────────────────────────────────────────────
+console.log(JSON.stringify({ ...report, healthy }, null, 2));
+process.exit(healthy ? 0 : 1);

