+    for (var i = length - 1; i >= 0; i--) {
+      result[i] = (v & BigInt.from(0xff)).toInt();
+      v = v >> 8;
+    }
+    return result;
+  }
+
+  BigInt _bytesToBigInt(List<int> bytes) {
+    var result = BigInt.from(0);
+    for (var i = 0; i < bytes.length; i++) {
+      result = (result << 8) | BigInt.from(bytes[i]);
+    }
+    return result;
+  }
+
+  BigInt? _modSqrt(BigInt a, BigInt p) {
+    if (a == BigInt.zero) return BigInt.zero;
+    if (p == BigInt.from(2)) return a;
+
+    // Tonelli-Shanks algorithm
+    if (p % BigInt.from(4) == BigInt.from(3)) {
+      final exp = (p + BigInt.from(1)) ~/ BigInt.from(4);
+      return a.modPow(exp, p);
+    }
+
+    // For P-256, p ≡ 3 (mod 4)
+    return null; // Should not happen for P-256
+  }
+}
