+import 'dart:io';
+import 'dart:convert';
+import 'dart:typed_data';
+import 'package:test/test.dart';
+import 'package:xml_crypto/xml_crypto.dart';
+
+void main() {
+  group('ECDSA-SHA256 Signature Tests', () {
+    late String ecdsaPrivateKey;
+    late String ecdsaPublicKey;
+    late String xmlToSign;
+
+    setUpAll(() {
+      ecdsaPrivateKey = File('test/static/ecdsa_private.pem').readAsStringSync();
+      ecdsaPublicKey = File('test/static/ecdsa_public.pem').readAsStringSync();
+      xmlToSign = '<root><book Id="_0"><name>Harry Potter</name></book></root>';
+    });
+
+    test('ECDSA-SHA256 algorithm is registered', () {
+      final algo = SignedXml.signatureAlgorithms['http://www.w3.org/2001/04/xmldsig-more#ecdsa-sha256'];
+      expect(algo, isNotNull);
+      expect(algo!.algorithmName, equals('http://www.w3.org/2001/04/xmldsig-more#ecdsa-sha256'));
+    });
+
+    test('can sign XML with ECDSA key and verify signature', () {
+      final sig = SignedXml()
+        ..signatureAlgorithm = 'http://www.w3.org/2001/04/xmldsig-more#ecdsa-sha256'
+        ..signingKey = Uint8List.fromList(utf8.encode(ecdsaPrivateKey))
+        ..addReference("//*[local-name()='book']");
+
+      sig.computeSignature(xmlToSign);
+      final signedXml = sig.signedXml;
+
+      expect(signedXml, contains('<Signature'));
+      expect(signedXml, contains('ecdsa-sha256'));
+
+      // Verify the signature
+      final doc = signedXml;
+      final signature = SignedXml()
+        ..keyInfoProvider = SimpleKeyInfo(ecdsaPublicKey)
+        ..signatureAlgorithm = 'http://www.w3.org/2001/04/xmldsig-more#ecdsa-sha256';
+
+      // Extract signature element
+      final signatureMatch = RegExp(r'<Signature[^>]*>.*?</Signature>', multiLine: true, dotAll: true)
+          .firstMatch(doc);
+      expect(signatureMatch, isNotNull);
+
+      signature.loadSignature(signatureMatch!.group(0)!);
+      final isValid = signature.checkSignature(doc);
+
+      expect(isValid, isTrue, reason: 'Signature validation failed: ${signature.validationErrors}');
+    });
+
+    test('signature format is correct base64 of r||s concatenation', () {
+      final algo = SignedXml.signatureAlgorithms['http://www.w3.org/2001/04/xmldsig-more#ecdsa-sha256'] as ECDSASHA256;
+
+      // Sign a test message
+      final signature = algo.getSignature(
+        'test message',
+        Uint8List.fromList(utf8.encode(ecdsaPrivateKey)),
+      );
+
+      // Decode and verify length (P-256 = 32 bytes r + 32 bytes s = 64 bytes)
+      final decoded = base64Decode(signature);
+      expect(decoded.length, equals(64), reason: 'ECDSA P-256 signature should be 64 bytes');
+    });
+  });
+}
+
+class SimpleKeyInfo implements KeyInfoProvider {
+  final String publicKey;
+
+  SimpleKeyInfo(this.publicKey);
+
+  @override
+  String getKeyInfo(Uint8List? signingKey, String? prefix) {
+    return '<X509Data></X509Data>';
+  }
+
+  @override
+  Uint8List? getKey(String? keyInfo) {
+    return Uint8List.fromList(utf8.encode(publicKey));
+  }
+}
