+class ECDSASHA256 implements SignatureAlgorithm {
+  static final String _algorithmUri = 'http://www.w3.org/2001/04/xmldsig-more#ecdsa-sha256';
+  
+  static final ECDomainParameters _curveParams = ECDomainCurve('prime256v1');
+
+  @override
+  String get algorithmName => _algorithmUri;
+
+  @override
+  String getSignature(String xml, Uint8List signingKey,
+      [CalculateSignatureCallback? callback]) {
+    final privateKeyPem = utf8.decode(signingKey);
+    final d = _parsePrivateKey(privateKeyPem);
+    final params = ECPrivateKeyParameters(d, _curveParams);
+    final signer = ECDSASigner(SHA256Digest());
+    signer.init(true, params);
+    final sig = signer.generateSignature(utf8.encode(xml));
+    final r = sig.r.toUnsigned(32);
+    final s = sig.s.toUnsigned(32);
+    // P-256 curve order is 32 bytes
+    final rBytes = _bigIntToBytes(r, 32);
+    final sBytes = _bigIntToBytes(s, 32);
+    final rawSignature = Uint8List(64);
+    rawSignature.setRange(0, 32, rBytes);
+    rawSignature.setRange(32, 64, sBytes);
+    final result = base64Encode(rawSignature);
+    if (callback != null) callback(null, result);
+    return result;
+  }
+
+  @override
+  bool verifySignature(String xml, Uint8List key, String signatureValue,
+      [ValidateSignatureCallback? callback]) {
+    final publicKeyPem = utf8.decode(key);
+    final q = _parsePublicKey(publicKeyPem);
+    final params = ECPublicKeyParameters(q, _curveParams);
+    final verifier = ECDSASigner(SHA256Digest());
+    verifier.init(false, params);
+    // Decode Base64 signature
+    final rawSignature = base64Decode(signatureValue);
+    // P-256 curve order is 32 bytes per component
+    final componentLen = 32;
+    if (rawSignature.length < 64) {
+      if (callback != null) {
+        callback(ArgumentError('Invalid ECDSA signature length: \${rawSignature.length}'), false);
+        return false;
+      }
+    }
+    // Extract r and s, handle non-standard signatures with missing leading zeros
+    final rBytes = _padToBytes(rawSignature.sublist(0, componentLen), componentLen);
+    final sLen = rawSignature.length - componentLen;
+    final sBytes = _padToBytes(rawSignature.sublist(componentLen, componentLen + sLen), componentLen);
+    final r = _bytesToBigInt(rBytes);
+    final s = _bytesToBigInt(sBytes);
+    final sig = ECDSASignature(r, s);
+    final res = verifier.verifySignature(utf8.encode(xml), sig);
+    if (callback != null) callback(null, res);
+    return res;
+  }
+
+  Uint8List _padToBytes(List<int> bytes, int length) {
+    if (bytes.length >= length) return Uint8List.fromList(bytes.sublist(0, length));
+    final padded = Uint8List(length);
+    padded.setRange(length - bytes.length, length, bytes);
+    return padded;
+  }
+
+  Uint8List _bigIntToBytes(BigInt value, int length) {
+    var hex = value.toRadixString(16);
+    if (hex.length % 2 != 0) hex = '0\$hex';
+    final bytes = <int>[];
+    for (var i = 0; i < hex.length; i += 2) {
+      bytes.add(int.parse(hex.substring(i, i + 2), radix: 16));
+    }
+    if (bytes.length >= length) return Uint8List.fromList(bytes.sublist(bytes.length - length));
+    final padded = Uint8List(length);
+    padded.setRange(length - bytes.length, length, bytes);
+    return padded;
+  }
+
+  BigInt _bytesToBigInt(List<int> bytes) {
+    var hex = '';
+    for (final b in bytes) {
+      hex += b.toRadixString(16).padLeft(2, '0');
+    }
+    return BigInt.parse(hex, radix: 16);
+  }
+
+  BigInt _parsePrivateKey(String pem) {
+    final lines = pem.split('\n');
+    final base64 = lines.where((l) => !l.startsWith('-----')).join('');
+    final keyData = base64Decode(base64);
+    final asn1 = ASN1Parser(keyData);
+    final sequence = asn1.nextObject() as ASN1Sequence;
+    final key = sequence.elements![0];
+    if (key is ASN1Integer) {
+      return key.valueAsBigInt!;
+    }
+    throw ArgumentError('Invalid ECDSA private key');
+  }
+
+  ECPoint _parsePublicKey(String pem) {
+    final lines = pem.split('\n');
+    final base64 = lines.where((l) => !l.startsWith('-----')).join('');
+    final keyData = base64Decode(base64);
+    final asn1 = ASN1Parser(keyData);
+    final sequence = asn1.nextObject() as ASN1Sequence;
+    final publicKeyBitString = sequence.elements![1] as ASN1BitString;
+    final publicKeyBytes = publicKeyBitString.stringValues!;
+    final asn1Public = ASN1Parser(Uint8List.fromList(publicKeyBytes));
+    final publicKeySeq = asn1Public.nextObject() as ASN1Sequence;
+    final x = (publicKeySeq.elements![0] as ASN1Integer).valueAsBigInt!;
+    final y = (publicKeySeq.elements![1] as ASN1Integer).valueAsBigInt!;
+    return _curveParams.curve.point(x, y)!;
+  }
+}
