+      final signedXml = SignedXml();
+      signedXml.signingKey = privateKey;
+      signedXml.keyInfoProvider = KeyInfoProvider();
+      
+      final signature = signedXml.computeSignature(xml, {
+        'signatureAlgorithm': 'http://www.w3.org/2001/04/xmldsig-more#ecdsa-sha256',
+      });
+      
+      // Extract the raw signature value and truncate some leading zeros
+      final doc = parseFromString(signature);
+      final sigValue = doc.rootElement
+          .findAllElements('SignatureValue')
+          .first
+          .innerText
+          .replaceAll(RegExp(r'\s'), '');
+      
+      // Decode base64 signature
+      final rawSig = base64Decode(sigValue);
