+// jumpToPanel moves the cursor to the first row of the left panel
+// (first PROJECTS row) when left=true, or the first row of the right
+// panel (first WORKERS row, or first agent if no workers) when
+// left=false. If the target panel is empty, sets a flash message
+// and does not move the cursor.
+func (m *Model) jumpToPanel(left bool) {
+	rows := m.dashboardRows()
+	if len(rows) == 0 {
+		return
+	}
+	if left {
+		// Find first PROJECTS row
+		for i, row := range rows {
+			if row.kind == rowProject {
+				m.dashCursor = i
+				return
+			}
+		}
+		// No PROJECTS rows — do nothing
+		return
+	}
+	// Right panel: first WORKERS row, or first agent row if no workers
+	for i, row := range rows {
+		if row.kind == rowWorker {
+			m.dashCursor = i
+			return
+		}
+	}
+	// No workers; find first agent row
+	for i, row := range rows {
+		if row.kind == rowAgent {
+			m.dashCursor = i
+			return
+		}
+	}
+	// Right panel is empty — show flash message
+	m.flash = &flashMsg{
+		msg:     "right panel is empty",
+		kind:    flashInfo,
+		addedAt: time.Now(),
+	}
+}
+
 // View renders the current state. Called by bubbletea on every model
 // update. Keep this pure: no I/O, no time.Now(), no surprises.
