+		Projects: []*ProjectRow{{Name: "demo", RepoSlug: "demo"}},
+		Workers: []*WorkerRow{
+			{Project: "demo", Slug: "feat-1a2b"},
+			{Project: "demo", Slug: "feat-3c4d"},
+		},
+		LoadedAt: time.Now(),
+	}
+	m.records = append(m.records, sampleAgent("agent01"))
+
+	// Cursor on the project row (top of LEFT panel).
+	m.dashCursor = 0
