@@ -0,0 +1,33 @@
+/**
+ * Formats a date into a human-readable elapsed time in Portuguese.
+ * Examples: "agora", "5 min", "2h", "1d 3h", or full date if older than a week.
+ */
+export function timeAgo(date: string | Date): string {
+  const now = new Date();
+  const past = typeof date === 'string' ? new Date(date) : date;
+  const diffMs = now.getTime() - past.getTime();
+  const diffSec = Math.floor(diffMs / 1000);
+  const diffMin = Math.floor(diffSec / 60);
+  const diffHour = Math.floor(diffMin / 60);
+  const diffDay = Math.floor(diffHour / 24);
+
+  if (diffSec < 60) {
+    return 'agora';
+  }
+  if (diffMin < 60) {
+    return `${diffMin} min`;
+  }
+  if (diffHour < 24) {
+    return `${diffHour}h`;
+  }
+  if (diffDay <= 7) {
+    const hours = diffHour % 24;
+    if (hours > 0) {
+      return `${diffDay}d ${hours}h`;
+    }
+    return `${diffDay}d`;
+  }
+
+  // Older than a week: return full date in pt-BR
+  return past.toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit', year: 'numeric' });
+}

