+import { cn } from './cn';
+
+/**
+ * Formata uma data em tempo relativo em português.
+ * - "agora" para menos de 1 minuto
+ * - "X min" para menos de 1 hora
+ * - "Xh" para menos de 1 dia
+ * - "Xd Xh" para menos de 1 semana
+ * - data completa se mais de 7 dias
+ */
+export function timeAgo(date: string | Date): string {
+  const d = typeof date === 'string' ? new Date(date) : date;
+  const now = new Date();
+  const diffMs = now.getTime() - d.getTime();
+  const diffSec = Math.floor(diffMs / 1000);
+  const diffMin = Math.floor(diffSec / 60);
+  const diffHour = Math.floor(diffMin / 60);
+  const diffDay = Math.floor(diffHour / 24);
+
+  if (diffSec < 60) return 'agora';
+  if (diffMin < 60) return `${diffMin} min`;
+  if (diffDay < 1) return `${diffHour}h`;
+  if (diffDay < 7) {
+    const days = diffDay;
+    const hours = diffHour % 24;
+    return hours > 0 ? `${days}d ${hours}h` : `${days}d`;
+  }
+  return d.toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit', year: 'numeric' });
+}
+
+export { cn };

