+import { useState } from 'react';
+import ReactMarkdown from 'react-markdown';
+import { supabase } from '../lib/supabaseClient';
+import { testConversationData } from '../data/testData';
+
+interface Message {
+  role: 'user' | 'assistant';
+  content: string;
+}
+
+export default function Discussions() {
+  const [messages, setMessages] = useState<Message[]>([]);
+  const [input, setInput] = useState('');
+  const [isLoading, setIsLoading] = useState(false);
+
+  const handleSubmit = async (e: React.FormEvent) => {
+    e.preventDefault();
+    if (!input.trim() || isLoading) return;
+
+    const userMessage = input.trim();
+    setInput('');
+    setIsLoading(true);
+
+    // Add user message to chat history
+    const updatedMessages = [...messages, { role: 'user' as const, content: userMessage }];
+    setMessages(updatedMessages);
+
+    try {
+      // Call the Supabase Edge Function
+      const response = await fetch(`${import.meta.env.VITE_SUPABASE_URL}/functions/v1/discussions`, {
+        method: 'POST',
+        headers: {
+          'Content-Type': 'application/json',
+          'Authorization': `Bearer ${import.meta.env.VITE_SUPABASE_ANON_KEY}`,
+        },
+        body: JSON.stringify({ messages: updatedMessages }),
+      });
+
+      if (!response.ok) {
+        const errorData = await response.json();
+        throw new Error(errorData.error || 'Failed to get response');
+      }
+
+      const data = await response.json();
+      
+      // Add AI response to chat history (rendered as Markdown)
+      setMessages(prev => [...prev, { role: 'assistant', content: data.message }]);
+    } catch (error) {
+      console.error('Error sending message:', error);
+      setMessages(prev => [...prev, { 
+        role: 'assistant', 
+        content: 'Sorry, I encountered an error. Please try again.' 
+      }]);
+    } finally {
+      setIsLoading(false);
+    }
+  };
+
+  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
+    if (e.key === 'Enter' && !e.shiftKey) {
+      e.preventDefault();
+      handleSubmit(e);
+    }
+  };
+
+  return (
+    <section className="h-screen flex flex-col bg-gray-100">
+      <div className="flex-1 overflow-y-auto p-6">
+        <div className="max-w-2xl mx-auto space-y-4">
+          {messages.map((message, index) => (
+            <div
+              key={index}
+              className={`p-4 rounded-lg ${
+                message.role === 'user'
+                  ? 'bg-blue-500 text-white ml-auto max-w-xs'
+                  : 'bg-white text-gray-800 mr-auto max-w-md shadow'
+              }`}
+            >
+              {message.role === 'assistant' ? (
+                <ReactMarkdown>{message.content}</ReactMarkdown>
+              ) : (
+                <p>{message.content}</p>
+              )}
+            </div>
+          ))}
+          {isLoading && (
+            <div className="bg-white text-gray-800 mr-auto max-w-md shadow p-4 rounded-lg">
+              <p className="text-gray-500">Thinking...</p>
+            </div>
+          )}
+        </div>
+      </div>
+      
+      <form onSubmit={handleSubmit} className="border-t bg-white p-4">
+        <div className="max-w-2xl mx-auto flex gap-2">
+          <textarea
+            value={input}
+            onChange={(e) => setInput(e.target.value)}
+            onKeyDown={handleKeyDown}
+            placeholder="Type your message..."
+            className="flex-1 border rounded-lg p-3 resize-none"
+            rows={2}
+            disabled={isLoading}
+          />
+          <button
+            type="submit"
+            disabled={isLoading || !input.trim()}
+            className="bg-black text-white px-6 py-2 rounded-lg disabled:bg-gray-400"
+          >
+            Submit
+          </button>
+        </div>
+      </form>
+    </section>
+  );
+}
