+import { createClient, SupabaseClient } from "@supabase/supabase-js";
+
+const corsHeaders = {
+  'Access-Control-Allow-Origin': '*',
+  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
+};
+
+const ANTHROPIC_API_URL = 'https://api.anthropic.com/v1/messages';
+const ANTHROPIC_API_KEY = Deno.env.get('ANTHROPIC_API_KEY');
+
+const SYSTEM_PROMPT = `You are a discovery consultant helping clients define their project requirements. Your role is to:
+
+1. Ask ONE question at a time to understand the client's needs
+2. Avoid using markdown formatting or special characters in your responses - use plain text only
+3. Cover key areas: project goals, target audience, budget, timeline, and any constraints
+4. After gathering sufficient information, provide a structured summary in this format:
+
+**Project Summary:**
+- **Goals:** [brief description]
+- **Target Audience:** [who this is for]
+- **Budget:** [budget range if mentioned]
+- **Timeline:** [expected delivery]
+- **Key Requirements:** [main features/constraints]
+
+Remember to ask one focused question at a time and be conversational but professional.`;
+
+Deno.serve(async (req) => {
+  if (req.method === 'OPTIONS') {
+    return new Response('ok', { headers: corsHeaders });
+  }
+
+  try {
+    const { messages } = await req.json();
+
+    if (!messages || !Array.isArray(messages)) {
+      return new Response(
+        JSON.stringify({ error: 'Invalid messages format' }),
+        { status: 400, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
+      );
+    }
+
+    const response = await fetch(ANTHROPIC_API_URL, {
+      method: 'POST',
+      headers: {
+        'Content-Type': 'application/json',
+        'x-api-key': ANTHROPIC_API_KEY,
+        'anthropic-version': '2023-06-01',
+        'anthropic-dangerous-direct-browser-access': 'true',
+      },
+      body: JSON.stringify({
+        model: 'claude-sonnet-4-20250514',
+        max_tokens: 1024,
+        system: SYSTEM_PROMPT,
+        messages: messages,
+      }),
+    });
+
+    if (!response.ok) {
+      const errorData = await response.text();
+      return new Response(
+        JSON.stringify({ error: `Anthropic API error: ${response.status}`, details: errorData }),
+        { status: response.status, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
+      );
+    }
+
+    const data = await response.json();
+    const aiMessage = data.content[0].text;
+
+    return new Response(
+      JSON.stringify({ message: aiMessage }),
+      { status: 200, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
+    );
+  } catch (error: unknown) {
+    const message = error instanceof Error ? error.message : 'Unknown error';
+    return new Response(
+      JSON.stringify({ error: message }),
+      { status: 500, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
+    );
+  }
+});

