+#!/usr/bin/env node
+
+import { createHash } from 'node:crypto';
+import { existsSync, readFileSync, readdirSync, statSync } from 'node:fs';
+import { homedir } from 'node:os';
+import { dirname, join, resolve } from 'node:path';
+import { fileURLToPath } from 'node:url';
+
+const __filename = fileURLToPath(import.meta.url);
+const __dirname = dirname(__filename);
+const repoRoot = resolve(__dirname, '..');
+
+const OWNED_PATTERNS = ['.claude-plugin', 'commands', 'scripts', 'README.md'];
+
+function isOwnedPath(relPath) {
+  const parts = relPath.split(/[/\\]/);
+  return OWNED_PATTERNS.some((p) => parts.includes(p) || relPath === p);
+}
+
+function readJson(path) {
+  return JSON.parse(readFileSync(path, 'utf8'));
+}
+
+function getRepoVersion() {
+  const versionPath = resolve(repoRoot, 'plugins/version.json');
+  if (!existsSync(versionPath)) return null;
+  try {
+    return readJson(versionPath).version;
+  } catch {
+    return null;
+  }
+}
+
+function getInstalledPluginPath(marketplace, name, version) {
+  const codexHome = process.env.CODEX_HOME ?? resolve(homedir(), '.codex');
+  const paths = [
+    resolve(codexHome, 'plugins/cache', marketplace, name, version),
+    resolve(codexHome, 'plugins/cache', marketplace, 'circuit-next', version),
+  ];
+  for (const p of paths) {
+    if (existsSync(p)) return p;
+  }
+  return null;
+}
+
+function getClaudioPluginPaths(version) {
+  const home = process.env.HOME ?? '';
+  const paths = [
+    resolve(home, '.claude/plugins/cache/circuit-next/circuit', version),
+    resolve(home, '.claude/plugins/user/circuit-next/circuit', version),
+  ];
+  for (const p of paths) {
+    if (existsSync(p)) return p;
+  }
+  return null;
+}
+
+function walkOwnedFiles(root) {
+  if (!existsSync(root)) return [];
+  const result = [];
+  const stack = [''];
+  while (stack.length > 0) {
+    const relDir = stack.pop();
+    const absDir = resolve(root, relDir);
+    if (!existsSync(absDir)) continue;
+    for (const entry of readdirSync(absDir, { withFileTypes: true })) {
+      const relPath = join(relDir, entry.name);
+      if (entry.isDirectory()) {
+        stack.push(relPath);
+      } else if (entry.isFile() && isOwnedPath(relPath)) {
+        const content = readFileSync(resolve(root, relPath));
+        const hash = createHash('sha256').update(content).digest('hex');
+        result.push({ rel: relPath, hash });
+      }
+    }
+  }
+  return result.sort((a, b) => a.rel.localeCompare(b.rel));
+}
+
+function comparePackageTree(sourceRoot, targetRoot) {
+  if (!existsSync(targetRoot)) return { status: 'missing' };
+  if (!statSync(targetRoot).isDirectory()) return { status: 'stale', details: 'target is not a directory' };
+
+  const sourceFiles = walkOwnedFiles(sourceRoot);
+  const targetFiles = walkOwnedFiles(targetRoot);
+
+  const sourceMap = new Map(sourceFiles.map((f) => [f.rel, f.hash]));
+  const targetMap = new Map(targetFiles.map((f) => [f.rel, f.hash]));
+
+  const missingOrStale = [];
+  for (const [rel, hash] of sourceMap) {
+    if (!targetMap.has(rel)) {
+      missingOrStale.push(`missing: ${rel}`);
+    } else if (targetMap.get(rel) !== hash) {
+      missingOrStale.push(`stale: ${rel}`);
+    }
+  }
+
+  const extraOwned = [];
+  for (const rel of targetMap.keys()) {
+    if (!sourceMap.has(rel)) {
+      extraOwned.push(rel);
+    }
+  }
+
+  if (missingOrStale.length > 0) {
+    return { status: 'stale', details: missingOrStale.join(', ') };
+  }
+  if (extraOwned.length > 0) {
+    return { status: 'extra-owned-files', details: extraOwned.join(', ') };
+  }
+  return { status: 'ok' };
+}
+
+function runPluginDoctor(pluginPath, runtimeScript) {
+  const doctorScript = resolve(pluginPath, runtimeScript);
+  if (!existsSync(doctorScript)) {
+    return { status: 'error', message: `doctor script not found: ${runtimeScript}` };
+  }
+  try {
+    const result = require('child_process').spawnSync(process.execPath, [doctorScript, 'doctor'], {
+      cwd: pluginPath,
+      env: { ...process.env, HOME: process.env.HOME, PATH: process.env.PATH },
