+  // Check launcher binary
+  const launcherPath = resolve(circuitDir, 'bin', 'circuit-next');
+  const launcherExists = existsSync(launcherPath);
+
+  if (circuitEntries.length > 1) {
+    return { 
+      status: 'invalid', 
+      details: `duplicate Circuit hooks: ${circuitEntries.length} entries found`,
+      hook_count: circuitEntries.length,
+    };
+  }
+
+  if (!launcherExists) {
+    return { 
+      status: 'invalid', 
+      details: 'launcher binary missing: bin/circuit-next',
+    };
+  }
+
+  if (circuitEntries.length === 0) {
+    return { status: 'missing' };
+  }
+
+  return { status: 'ok' };
+}
+
+function main() {
+  const repoVersion = getRepoVersion();
+  
+  const report = {
+    schema_version: 1,
+    repo_version: repoVersion,
+    claude_plugin: null,
+    codex_plugin: null,
+    codex_hook: null,
+    healthy: true,
+  };
+
+  // Check Claude plugin
+  const claudeSourcePath = resolve(repoRoot, 'plugins/claude');
+  if (repoVersion) {
+    const claudeInstalledPath = getClaudioPluginPaths(repoVersion);
+    if (claudeInstalledPath) {
+      const packageTree = comparePackageTree(claudeSourcePath, claudeInstalledPath);
+      const doctorResult = runPluginDoctor(claudeInstalledPath, 'scripts/circuit-next.mjs');
+      report.claude_plugin = {
+        version: repoVersion,
+        installed_path: claudeInstalledPath,
+        package_tree: packageTree,
+        runtime_doctor: doctorResult,
+      };
+      if (packageTree.status !== 'ok' || doctorResult.status !== 'bundled') {
+        report.healthy = false;
+      }
+    } else {
+      report.claude_plugin = {
+        version: repoVersion,
+        installed_path: null,
+        package_tree: { status: 'missing' },
+        runtime_doctor: { status: 'not installed' },
+      };
+      report.healthy = false;
+    }
+  }
+
+  // Check Codex plugin
+  const codexSourcePath = resolve(repoRoot, 'plugins/circuit');
+  const codexVersion = (() => {
+    try {
+      const manifest = resolve(codexSourcePath, '.codex-plugin/plugin.json');
+      if (existsSync(manifest)) {
+        return readJson(manifest).version;
+      }
+    } catch {}
+    return null;
+  })();
+
+  if (codexVersion) {
+    const codexInstalledPath = getInstalledPluginPath('circuit-next-local', 'circuit-next', codexVersion);
+    if (codexInstalledPath) {
+      const packageTree = comparePackageTree(codexSourcePath, codexInstalledPath);
+      report.codex_plugin = {
+        version: codexVersion,
+        installed_path: codexInstalledPath,
+        package_tree: packageTree,
+      };
+      if (packageTree.status !== 'ok') {
+        report.healthy = false;
+      }
+    } else {
+      report.codex_plugin = {
+        version: codexVersion,
+        installed_path: null,
+        package_tree: { status: 'missing' },
+      };
+      report.healthy = false;
+    }
+  }
+
+  // Check Codex hooks
+  report.codex_hook = checkCodexHooks();
+  if (report.codex_hook.status !== 'ok' && report.codex_hook.status !== 'missing') {
+    report.healthy = false;
+  }
+
+  console.log(JSON.stringify(report, null, 2));
+  process.exit(report.healthy ? 0 : 1);
+}
+
+main();

