+    ///
+    /// The in-plane 2×2 block of the lattice basis is Minkowski-reduced
+    /// before identification to correctly handle skewed unit cells while
+    /// preserving the layer-block form (c axis fixed).
+    pub fn from_lattice(
+        lattice: &LayerLattice,
+        prim_layer_operations: &Operations,
+        setting: LayerSetting,
+        epsilon: f64,
+    ) -> Result<Self, MoyoError> {
+        // Perform 2D Minkowski reduction on the in-plane components
+        // while preserving the c axis (third row/column)
+        let basis = lattice.basis();
+        let a = basis.column(0);
+        let b = basis.column(1);
+        let c = basis.column(2);
+
+        // Build 2x2 matrix for in-plane reduction (column-wise)
+        let mut basis_2d: nalgebra::Matrix2<f64> = nalgebra::Matrix2::new(
