+            a[1], b[1],
+        );
+
+        // Perform 2D Minkowski reduction
+        let (reduced_2d, trans_2d) = minkowski_reduce_2d(&basis_2d);
+
+        // Build the full 3x3 reduced basis (column-wise)
+        // Keep c axis unchanged, use reduced 2D block
+        let mut reduced_basis = nalgebra::Matrix3::identity();
+        reduced_basis.column_mut(0).copy_from(&nalgebra::Vector3::new(reduced_2d[(0, 0)], reduced_2d[(1, 0)], 0.0));
+        reduced_basis.column_mut(1).copy_from(&nalgebra::Vector3::new(reduced_2d[(0, 1)], reduced_2d[(1, 1)], 0.0));
