+        let reduced_lattice = LayerLattice::from_basis(&reduced_basis);
+
+        // Transform operations to the reduced basis
+        // The transformation from original to reduced is: T = trans_2d extended to 3x3
+        let mut trans_3d = nalgebra::Matrix3::<i32>::identity();
+        trans_3d[(0, 0)] = trans_2d[(0, 0)];
+        trans_3d[(0, 1)] = trans_2d[(0, 1)];
+        trans_3d[(1, 0)] = trans_2d[(1, 0)];
+        trans_3d[(1, 1)] = trans_2d[(1, 1)];
+
+        let prim_trans_mat = UnimodularTransformation::new(trans_3d, [0.0, 0.0, 0.0]);
