+// 2D Minkowski reduction for layer groups
+// Only reduces the in-plane components (x, y) while preserving z
+pub fn minkowski_reduce_2d(basis: &nalgebra::Matrix2<f64>) -> (nalgebra::Matrix2<f64>, nalgebra::Matrix2<i32>) {
+    let mut reduced_basis = *basis;
+    let mut trans_mat = nalgebra::Matrix2::<i32>::identity();
+
+    let eps = 1e-8;
+
+    // Simple 2D reduction: swap if needed, then adjust
+    loop {
+        let len0 = reduced_basis.column(0).norm();
+        let len1 = reduced_basis.column(1).norm();
+
+        if len0 > len1 + eps {
+            // Swap columns
+            for i in 0..2 {
+                let temp = reduced_basis[(i, 0)];
+                reduced_basis[(i, 0)] = reduced_basis[(i, 1)];
+                reduced_basis[(i, 1)] = temp;
+            }
+            // Update transformation
+            trans_mat = nalgebra::Matrix2::new(0, 1, 1, 0) * trans_mat;
+            continue;
+        }
+
+        // Check if reduction is needed: project column 1 onto column 0
+        let dot01 = reduced_basis.column(0).dot(&reduced_basis.column(1));
+        let proj = dot01 / (len0 * len0);
+
+        if proj.abs() > 0.5 + eps {
+            // Need to adjust
+            let n = (proj + 0.5).round() as i32;
+            for i in 0..2 {
+                reduced_basis[(i, 1)] -= n as f64 * reduced_basis[(i, 0)];
+            }
+            // Update transformation
+            let mut adjust = nalgebra::Matrix2::<i32>::identity();
+            adjust[(0, 1)] = -n;
+            trans_mat = adjust * trans_mat;
+            continue;
+        }
+
+        // Check if we need to negate
+        if reduced_basis.column(0)[0] < -eps {
+            reduced_basis.column_mut(0).scale_mut(-1.0);
+            trans_mat = nalgebra::Matrix2::new(-1, 0, 0, 1) * trans_mat;
+            continue;
+        }
+
+        break;
+    }
+
+    (reduced_basis, trans_mat)
+}
