+impl LayerGroup {
+    /// Identify a layer group from a lattice and primitive layer-cell operations.
+    ///
+    /// This performs 2D Minkowski reduction on the in-plane basis block before
+    /// identification to correctly handle skewed unit cells while preserving the
+    /// layer-block form (c axis fixed).
+    pub fn from_lattice(
+        lattice: &LayerLattice,
+        prim_layer_operations: &Operations,
+        setting: LayerSetting,
+        epsilon: f64,
+    ) -> Result<Self, MoyoError> {
+        use crate::math::minkowski::{lift_2d_to_3d, minkowski_reduce_2d};
+        use nalgebra::Matrix2;
+
+        // Extract in-plane 2x2 block: rows 0-1, cols 0-1
+        let basis = lattice.basis();
+        let inplane_block = Matrix2::<f64>::new(
+            basis[[0, 0]], basis[[0, 1]],
+            basis[[1, 0]], basis[[1, 1]],
+        );
+
+        // Apply 2D Minkowski reduction
+        let (reduced_2d, trans_2d) = minkowski_reduce_2d(&inplane_block);
+        
+        // Check if reduction was needed (basis not already reduced)
+        let needs_reduction = !crate::math::minkowski::is_minkowski_reduced_2d(&inplane_block);
+
+        if needs_reduction {
+            // Lift 2D transformation to 3D (identity in c direction)
+            let trans_3d = lift_2d_to_3d(&trans_2d);
+            let to_reduced = UnimodularTransformation::from_linear(trans_3d);
+
+            // Transform operations using the reduction matrix
+            let reduced_prim_operations = to_reduced.transform_operations(prim_layer_operations);
+
+            // Identify on reduced operations
+            let reduced_layer_group = Self::new(&reduced_prim_operations, setting, epsilon)?;
+
+            // Compose transformations: reduction then identification
+            return Ok(Self {
+                number: reduced_layer_group.number,
+                hall_number: reduced_layer_group.hall_number,
+                transformation: reduced_layer_group.transformation * to_reduced,
+            });
+        }
+
+        // No reduction needed, use standard identification
+        Self::new(prim_layer_operations, setting, epsilon)
+    }
+}
