+	cd := resp.Header.Get("Content-Disposition")
+	if !strings.Contains(cd, `filename="space.md"`) {
+		t.Fatalf("Content-Disposition missing space in quoted filename: %s", cd)
+	}
+	// filename* should have the space URL-encoded.
+	if !strings.Contains(cd, "space%20.md") {
+		t.Fatalf("Content-Disposition missing space in filename*: %s", cd)
+	}
+
+	// Also test "with space.md".
+	resp2, raw2 := apiGet(t, ts.URL+"/repos/"+repo.Prefix+"/documents/with%20space.md/download")
