+	cd2 := resp2.Header.Get("Content-Disposition")
+	if !strings.Contains(cd2, `filename="with space.md"`) {
+		t.Fatalf("Content-Disposition missing space in quoted filename: %s", cd2)
+	}
+	// filename* should have the space URL-encoded.
+	if !strings.Contains(cd2, "with+space.md") && !strings.Contains(cd2, "with%20space.md") {
+		t.Fatalf("Content-Disposition missing space in filename*: %s", cd2)
+	}
