+// handleDocumentDownload serves the raw body of a document for download.
+// It is a pure read operation: no audit entry, no X-Actor, no dry-run.
+func (d deps) handleDocumentDownload(w http.ResponseWriter, r *http.Request) {
+	repo, ok := resolveRepoFromPath(w, r, d.store)
+	if !ok {
+		return
+	}
+	filename := r.PathValue("filename")
+	clean, err := store.ValidateDocFilenameStrict(filename)
+	if err != nil {
+		writeError(w, http.StatusBadRequest, "invalid_input", err.Error(), map[string]any{"field": "filename"})
+		return
+	}
+	doc, err := d.store.GetDocumentByFilename(repo.ID, clean, true)
+	if err != nil {
+		if errors.Is(err, store.ErrNotFound) {
+			writeError(w, http.StatusNotFound, "not_found", "document not found", nil)
+			return
+		}
+		status, code := statusForError(err)
+		writeError(w, status, code, err.Error(), nil)
+		return
+	}
+	// Content-Disposition with both quoted filename and RFC 5987 filename*.
+	// The filename* uses URL/escaped encoding per RFC 5987.
+	w.Header().Set("Content-Type", "text/markdown; charset=utf-8")
+	w.Header().Set("Content-Disposition", `attachment; filename="`+doc.Filename+`"; filename*=UTF-8''`+url.QueryEscape(doc.Filename))
+	w.WriteHeader(http.StatusOK)
+	w.Write([]byte(doc.Content))
+}
+
 // resolveDocumentOnRepo pulls {filename} from the URL, validates it, and
 // fetches the row scoped to repo. 404 on miss; 400 on a validation
 // failure since the URL value can't satisfy any document at that point.
